import{_ as a,o as t,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Developer Hub Overview","description":"","frontmatter":{"title":"Developer Hub Overview","slug":"developer-hub-overview"},"headers":[],"relativePath":"developer-hub/developer-hub-overview.md","filePath":"developer-hub/developer-hub-overview.md"}'),i={name:"developer-hub/developer-hub-overview.md"};function o(s,e,p,c,d,l){return t(),r("div",null,[...e[0]||(e[0]=[n('<p>Welcome to Branch&#39;s <strong>Developer Hub</strong>, your technical resource for integrating Branch&#39;s products into your applications and implementing advanced features across mobile, web, and server-side environments.</p><h2 id="what-is-developer-hub" tabindex="-1">What is Developer Hub? <a class="header-anchor" href="#what-is-developer-hub" aria-label="Permalink to &quot;What is Developer Hub?&quot;">​</a></h2><p>Developer Hub is a dedicated documentation workspace designed for developers, engineers, and technical teams implementing Branch. Whether you&#39;re integrating SDKs, configuring attribution methods, or building custom solutions with our APIs, you&#39;ll find implementation guides, code samples, and technical references here to support your development.</p><p>This hub focuses on technical implementation, from SDK integration and API usage to advanced configurations and data privacy compliance.</p><h2 id="what-s-inside" tabindex="-1">What&#39;s inside <a class="header-anchor" href="#what-s-inside" aria-label="Permalink to &quot;What&#39;s inside&quot;">​</a></h2><p><a href="./get-started-developer-hub.html">Get Started</a></p><p>New to Branch development? Start here to understand the basics, set up your account, and learn about the platform&#39;s technical architecture.</p><p><a href="./branch-sdks.html">Branch SDKs</a></p><p>Integrate Branch&#39;s SDKs for iOS, Android, React Native, Flutter, Unity, and other platforms to enable deep linking and attribution in your apps.</p><p><a href="./apis.html">Branch APIs</a></p><p>Use Branch&#39;s REST APIs to programmatically create links, manage campaigns, access analytics data, and build custom integrations.</p><p><a href="./methodology.html">Methodology</a></p><p>Understand Branch&#39;s technical approach to attribution, matching, and data collection.</p><p><a href="./tracking.html">Tracking</a></p><p>Implement event tracking, retrieve attribution data, and configure how Branch captures user interactions across your applications.</p><p><a href="https://help.branch.io/developer-hub/docs/deep-linking" target="_blank" rel="noreferrer">Deep Linking</a></p><p>Implement deep linking to route users to specific content within your app, handle deferred deep links for new users, and create seamless cross-platform experiences.</p><p><a href="https://help.branch.io/developer-hub/docs/ads-for-developers" target="_blank" rel="noreferrer">Ads</a></p><p>Integrate Branch with ad partners, configure attribution settings for paid campaigns, and set up Postbacks for non-SANs.</p><p><a href="./journeys.html">Journeys</a></p><p>Configure and customize Journeys (smart banners) to drive app adoption from mobile web, including advanced targeting and routing logic.</p><p><a href="./email.html">Email</a></p><p>Integrate Branch with email service providers to enable click tracking and deep linking from email campaigns.</p><p><a href="./advanced-data-feeds.html">Data Feeds</a></p><p>Configure webhooks and data exports to send Branch data to your analytics platforms, data warehouses, and internal systems in real-time.</p><p><a href="./additional-use-cases.html">Additional Use Cases</a></p><p>Implement advanced features including push notification deep linking, SEO and AIO optimization, and custom Deepview configurations.</p><p><a href="./data-privacy-index.html">Data Privacy</a></p><p>Implement privacy features, configure content security policies, manage user data preferences, restrict data processing, and filter ad network data to meet regulatory requirements.</p><h2 id="how-to-navigate" tabindex="-1">How to navigate <a class="header-anchor" href="#how-to-navigate" aria-label="Permalink to &quot;How to navigate&quot;">​</a></h2><p>Use the left sidebar to browse topics, or use the search function (CMD+K) to quickly find specific information. Each section contains technical documentation, code examples, and implementation guides to help you integrate Branch into your applications.</p><p>Article folders are organized primarily by feature and implementation area, making it easy to find the technical resources you need for your specific use case.</p><h2 id="need-marketer-resources" tabindex="-1">Need marketer resources? <a class="header-anchor" href="#need-marketer-resources" aria-label="Permalink to &quot;Need marketer resources?&quot;">​</a></h2><p>While Developer Hub focuses on technical implementation and SDK integration, Branch also provides resources for campaign creation and optimization. For guides on creating links, setting up campaigns, and accessing analytics, please visit <a href="./marketer-hub-overview.html">Marketer Hub</a>.</p>',34)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
